                                <button 
                                    onClick={() => setPhase('MATCHUP_LOTTERY')} 
                                    className="group relative px-24 py-6 bg-[#dcb06b] text-[#05090f] clip-corner-md font-cinzel font-black text-2xl tracking-[0.2em] hover:bg-white hover:scale-105 transition-all shadow-[0_0_50px_rgba(220,176,107,0.6)]"
                                >
                                    START BRACKET
                                </button>
                            )}

                            {!isGlobalRolling && !isGlobalRevealComplete && (
                                <button onClick={() => setPhase('MATCHUP_LOTTERY')} className="text-[#4a5f78] hover:text-[#dcb06b] text-[10px] font-orbitron font-bold uppercase tracking-widest border-b border-transparent hover:border-[#dcb06b] transition-all">
                                    Skip Animation &gt;&gt;
                                </button>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes scan {
                    0% { top: 0%; opacity: 0; }
                    10% { opacity: 1; }
                    90% { opacity: 1; }
                    100% { top: 100%; opacity: 0; }
                }
                @keyframes scan-gradient {
                    0% { top: -100%; }
                    100% { top: 100%; }
                }
            `}</style>
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="absolute top-6 left-6 z-[300]">
              <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
        </div>
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'MATCHUP_LOTTERY') return renderMatchupLottery();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  // Use a variable to handle depth spacing, similar to how 16 teams was handled
  const isDeepBracket = match.teams.length >= 14;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {/* Rename Modal UI */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className={`flex items-center justify-center relative py-20 ${isDeepBracket ? 'gap-20 md:gap-28' : 'gap-16 md:gap-24'}`}>
            {hasRoundOne && (
                <div className={`flex flex-col relative ${isDeepBracket ? 'gap-8' : 'gap-8'}`}>
                    {roundOneMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {match.teams.length === 14 ? (
                                // 14 Teams Special Connectors: First 4 matches are pairs (Fork), last 2 are singles (Straight)
                                <>
                                    {i < 4 && i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}
                                    {i >= 4 && <EnergyConnector type="straight" height={218} style={{top:'50%'}}/>}
                                </>
                            ) : (
                                i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>
                            )}
                        </div>
                    ))}
                </div>
            )}
            <div className={`flex flex-col relative ${isDeepBracket ? 'gap-[274px]' : 'gap-32'}`}>
                {quarterMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i % 2 === 0 && <EnergyConnector type="fork" height={isDeepBracket ? 458 : 338} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className={`flex flex-col relative ${isDeepBracket ? 'gap-[758px]' : 'gap-64'}`}>
                {semiMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i === 0 && <EnergyConnector type="fork" height={isDeepBracket ? 938 : 458} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roleName={wheelState.role} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
                <div className="text-white font-orbitron font-black text-2xl tracking-[0.4em]">{activeRoomId}</div>
            </div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-32 items-end mb-6">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-32"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER, RoleImagesActive } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const handleFilterClick = (val: string) => {
      setFilter(val as FilterType);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;

    // Pastikan panah dirender dua kali jika nilai mutlaknya adalah 2
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400 items-center justify-center">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500 items-center justify-center">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => handleFilterClick(val)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 gap-y-5 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          // Hirarki Status & Warna Trace Border
          if (player.isActive) {
            if (isMvp) {
              primaryColor = '#fbbf24'; // Emas
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; // Putih
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; // Merah
              else if (ws >= 4) primaryColor = '#f97316'; // Oren
              else if (ws >= 3) primaryColor = '#a855f7'; // Ungu
              else primaryColor = '#00d2ff'; // Biru Cyan

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>

              {/* DISCORD NAME BADGE - Placed ABOVE the card border */}
              {player.discordName && (
                  <div className="absolute -top-[14px] left-0 z-20 flex items-center gap-1.5 px-2 py-0.5 bg-[#5865F2] clip-corner-sm text-white skew-x-[-12deg] origin-bottom-left shadow-[0_-2px_10px_rgba(88,101,242,0.4)]">
                      <div className="skew-x-[12deg] flex items-center gap-1">
                          <svg className="w-2.5 h-2.5" viewBox="0 0 127 96" fill="none" xmlns="http://www.w3.org/2000/svg">
                              <path d="M107.701 8.04901C107.701 8.04901 98.7997 0.941655 88.5997 0C88.1997 0.541667 87.2997 2.04902 86.2997 3.34902C75.2997 1.84902 64.3997 1.84902 53.6997 3.34902C52.6997 2.04902 51.7997 0.541667 51.3997 0C41.1997 0.941655 32.2997 8.04901 32.2997 8.04901C13.8997 35.549 14.3997 62.449 16.8997 88.949C28.2997 97.449 43.0997 102.449 57.8997 102.449C61.3997 97.749 64.3997 92.749 66.8997 87.449C61.6997 85.449 56.7997 82.949 52.1997 80.049C53.4997 79.149 54.6997 78.149 55.7997 77.149C82.3997 89.449 111.4 89.449 137.6 77.149C138.8 78.249 140 79.249 141.3 80.049C136.7 82.949 131.8 85.449 126.6 87.449C129.1 92.749 132.1 97.749 135.6 102.449C150.4 102.449 165.2 97.449 176.6 88.949C179.3 61.249 174.5 35.549 156.1 8.04901C156.1 8.04901 147.2 0.941655 137 0C136.6 0.541667 135.7 2.04902 134.7 3.34902C124 1.84902 113.1 1.84902 102.1 3.34902C101.1 2.04902 100.2 0.541667 99.8003 0C89.6003 0.941655 80.7003 8.04901 80.7003 8.04901ZM64.0997 68.349C56.2997 68.349 49.8997 61.249 49.8997 52.549C49.8997 43.849 56.0997 36.749 64.0997 36.749C72.0997 36.749 78.4997 43.849 78.2997 52.549C78.2997 61.249 72.0997 68.349 64.0997 68.349ZM124.3 68.349C116.5 68.349 110.1 61.249 110.1 52.549C110.1 43.849 116.3 36.749 124.3 36.749C132.3 36.749 138.7 43.849 138.5 52.549C138.5 61.249 132.3 68.349 124.3 68.349Z" fill="white" transform="scale(0.65)"/>
                          </svg>
                          <span className="font-bold text-[8px] font-orbitron tracking-wider">{player.discordName}</span>
                      </div>
                  </div>
              )}

              {/* Animated Border Background */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/20">
                 {animationLayer}
              </div>

              {/* Inner Card content */}
              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/80 grayscale backdrop-blur-sm'}`}>

                {/* BENCHED STAMP - Only for inactive players */}
                {!player.isActive && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                        <div className="absolute inset-0 bg-red-900/10 mix-blend-overlay"></div>
                        <div className="rotate-[-15deg] border-4 border-red-600/80 px-4 py-1 text-red-600/90 font-black text-2xl tracking-[0.3em] uppercase bg-black/40 backdrop-blur-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-pulse-fast">
                            BENCHED
                        </div>
                    </div>
                )}

                <div className="flex justify-between items-start mb-2 relative z-10">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => {
                            const icon = RoleImagesActive[r];
                            return (
                                <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase flex items-center gap-1 ${getRoleBadgeStyle(r)}`}>
                                    {icon && <img src={icon} className="w-3 h-3 object-contain" alt="" />}
                                    {r.split(' ')[0]}
                                </span>
                            );
                        })
                      )}
                    </div>
                  </div>

                  {/* Status Mini-Tags */}
                  <div className="flex flex-col items-end gap-1">
                    <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b] mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                    </button>

                    <div className="flex flex-col gap-1 items-end">
                       {/* MVP Mini-Tag */}
                       {isMvp && player.isActive && (
                         <div className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter bg-[#fbbf24] text-black clip-corner-sm shadow-[0_0_8px_rgba(251,191,36,0.6)]">
                            MVP
                         </div>
                       )}

                       {/* Win Streak Mini-Tag */}
                       {ws >= 2 && player.isActive && (
                         <div 
                           className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter text-white clip-corner-sm shadow-md"
                           style={{ backgroundColor: primaryColor }}
                         >
                            {ws} WS
                         </div>
                       )}
                    </div>
                  </div>
                </div>

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1 relative z-10">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => { onToggleActive(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => { onEdit(players.find(p => p.id === menuOpenId)!); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => { onRemove(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';
import { ConfirmModal } from './ConfirmModal';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onMinimize: () => void; // New Prop
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onMinimize, onCompleteMatch, onReroll, onStartBattle, onUpdatePlayer
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    isDestructive?: boolean;
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;
    const roleToReveal = displayRoles[nextIndex];
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) { startWheel('azure', roleToReveal); return; }
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) { startWheel('crimson', roleToReveal); return; }
  };

  const handleSkipAll = () => {
    setConfirmState({
      isOpen: true,
      title: "SKIP DRAFT",
      message: "Are you sure you want to skip the remaining draft reveals? This will reveal all players instantly.",
      onConfirm: () => {
        const allCards = new Set<string>();
        displayRoles.forEach(r => { 
          allCards.add(getCardId('azure', r)); 
          allCards.add(getCardId('crimson', r)); 
        });
        setRevealedCards(allCards);
        setCurrentRoleIndex(displayRoles.length - 1);
      }
    });
  };

  const handleAbort = () => {
    setConfirmState({
      isOpen: true,
      title: "ABORT BATTLE",
      message: "Are you sure you want to abort the current draft? All progress will be lost and you will return to the lobby.",
      isDestructive: true,
      onConfirm: () => onReset()
    });
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers.filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;
    setWheelState({ isOpen: true, type: 'draft', team, role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);
    if (candidates.length === 1) { onReroll(team, role, candidates[0]); return; }
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 
    setWheelState({ isOpen: true, type: 'reroll', team, role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidateNames, duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  const openRenameModal = (player: Player) => {
    setRenameState({ isOpen: true, player, newName: player.name });
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  if (viewState === 'evaluation' && winningTeam) return (
     <>
        <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                LOBBY
            </Button>
        </div>
        <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />
     </>
  );

  if (viewState === 'celebration' && winningTeam) return (
      <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} azureTeamName={match.azureTeamName} crimsonTeamName={match.crimsonTeamName} onDismiss={handleCelebrationDismiss} />
  );

  if (viewState === 'transition') return (
    <>
       <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                LOBBY
            </Button>
       </div>
       <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} azureTeamName={match.azureTeamName} crimsonTeamName={match.crimsonTeamName} onComplete={handleTransitionComplete} />
    </>
  );

  if (viewState === 'final') return (
     <>
        <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                LOBBY
            </Button>
        </div>
        <MatchSummary match={match} onReset={handleMatchDecided} />
     </>
  );

  const renderPlayerCard = (role: Role, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;
    const isMvp = player?.isLastMatchMvp;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.6)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    // Override theme for MVP
    if (isMvp && !isCoach) {
        theme.border = 'border-yellow-400';
        theme.glow = 'shadow-[0_0_20px_#fbbf24]';
    }

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${team === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>

             {/* Discord Name + Logo */}
             {player?.discordName && (
                <div className={`flex items-center gap-1.5 mb-0.5 ${team === 'crimson' ? 'flex-row-reverse' : 'flex-row'}`}>
                    <svg className="w-3 h-3 text-[#5865F2]" viewBox="0 0 127 96" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M107.701 8.04901C107.701 8.04901 98.7997 0.941655 88.5997 0C88.1997 0.541667 87.2997 2.04902 86.2997 3.34902C75.2997 1.84902 64.3997 1.84902 53.6997 3.34902C52.6997 2.04902 51.7997 0.541667 51.3997 0C41.1997 0.941655 32.2997 8.04901 32.2997 8.04901C13.8997 35.549 14.3997 62.449 16.8997 88.949C28.2997 97.449 43.0997 102.449 57.8997 102.449C61.3997 97.749 64.3997 92.749 66.8997 87.449C61.6997 85.449 56.7997 82.949 52.1997 80.049C53.4997 79.149 54.6997 78.149 55.7997 77.149C82.3997 89.449 111.4 89.449 137.6 77.149C138.8 78.249 140 79.249 141.3 80.049C136.7 82.949 131.8 85.449 126.6 87.449C129.1 92.749 132.1 97.749 135.6 102.449C150.4 102.449 165.2 97.449 176.6 88.949C179.3 61.249 174.5 35.549 156.1 8.04901C156.1 8.04901 147.2 0.941655 137 0C136.6 0.541667 135.7 2.04902 134.7 3.34902C124 1.84902 113.1 1.84902 102.1 3.34902C101.1 2.04902 100.2 0.541667 99.8003 0C89.6003 0.941655 80.7003 8.04901 80.7003 8.04901ZM64.0997 68.349C56.2997 68.349 49.8997 61.249 49.8997 52.549C49.8997 43.849 56.0997 36.749 64.0997 36.749C72.0997 36.749 78.4997 43.849 78.2997 52.549C78.2997 61.249 72.0997 68.349 64.0997 68.349ZM124.3 68.349C116.5 68.349 110.1 61.249 110.1 52.549C110.1 43.849 116.3 36.749 124.3 36.749C132.3 36.749 138.7 43.849 138.5 52.549C138.5 61.249 132.3 68.349 124.3 68.349Z" fill="currentColor" />
                    </svg>
                    <span className="text-[9px] font-orbitron text-[#5865F2] font-bold tracking-wider">{player.discordName}</span>
                </div>
             )}

             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${team === 'azure' ? 'right-4' : 'left-4'}`}>
              <button onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }} className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all" title="Reroll Player"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); if(player) openRenameModal(player); }} className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all" title="Change Nickname"><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
           </div>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? match.azureTeamName : match.crimsonTeamName;
     buttonText = `SELECT ${nextTeam} ${formatRoleLabelShort(nextRoleName)}`;
  }

  return (
    <>
      <ConfirmModal isOpen={confirmState.isOpen} title={confirmState.title} message={confirmState.message} onConfirm={confirmState.onConfirm} onCancel={() => setConfirmState(prev => ({ ...prev, isOpen: false }))} isDestructive={confirmState.isDestructive} />
      {renameState.isOpen && (<div className="fixed inset-0 z-[1000] flex items-center justify-center p-4"><div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div><div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6"><h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3><input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus /><div className="flex gap-3"><Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button><Button onClick={submitRename} className="flex-1">CONFIRM</Button></div></div></div>)}

      {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={match.roomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={handleWheelCancel} />}
      <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">

        {/* TOP CONTROLS */}
        <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
           <div className="flex gap-3">
               <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                  LOBBY
               </Button>
               <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/60 text-red-500 hover:bg-red-900/20 text-xs px-6 shadow-[0_0_15px_rgba(239,68,68,0.2)]">
                  END SESSION
               </Button>
           </div>

           {/* ROOM ID CENTERED */}
           <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
