                                            );
                                        })}
                                    </div>
                                    <div className="h-1.5 w-full flex"><div className={`h-full flex-1 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b] shadow-[0_0_15px_#dcb06b]' : 'bg-[#1e3a5f]'}`}></div><div className="h-full w-4 bg-[#05090f]"></div><div className={`h-full w-8 transition-all duration-1000 ${isRevealed ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}></div></div>
                                </div>
                            </div>
                        );
                    })}
                    <div className="h-40 w-full shrink-0 col-span-full"></div>
                </div>
                <div className="fixed bottom-0 left-0 right-0 z-50 flex flex-col items-center">
                    <div className="h-1 w-full bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>
                    <div className="w-full bg-[#05090f]/90 backdrop-blur-xl p-6 md:p-8 flex flex-col items-center justify-center border-t border-[#dcb06b]/20 shadow-[0_-10px_50px_rgba(0,0,0,0.8)]">
                         <div className="pointer-events-auto flex flex-col items-center gap-4">
                            {!isGlobalRevealComplete ? (
                                <button onClick={handleStartGlobalReveal} disabled={isGlobalRolling} className={`group relative px-20 py-5 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-black text-xl tracking-[0.2em] hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 ${isGlobalRolling ? 'opacity-50 cursor-not-allowed' : 'shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:shadow-[0_0_50px_rgba(220,176,107,0.6)] animate-pulse'}`}><div className="absolute inset-0 bg-[#dcb06b] opacity-0 group-hover:opacity-10 transition-opacity"></div><span className="relative z-10 flex items-center gap-4">{isGlobalRolling ? (<><svg className="animate-spin h-6 w-6" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>DECRYPTING...</>) : (<>COMMENCE REVEAL</>)}</span></button>
                            ) : (
                                <button onClick={() => setPhase('MATCHUP_LOTTERY')} className="group relative px-24 py-6 bg-[#dcb06b] text-[#05090f] clip-corner-md font-cinzel font-black text-2xl tracking-[0.2em] hover:bg-white hover:scale-105 transition-all shadow-[0_0_50px_rgba(220,176,107,0.6)]">START BRACKET</button>
                            )}
                            {!isGlobalRolling && !isGlobalRevealComplete && (<button onClick={() => setPhase('MATCHUP_LOTTERY')} className="text-[#4a5f78] hover:text-[#dcb06b] text-[10px] font-orbitron font-bold uppercase tracking-widest border-b border-transparent hover:border-[#dcb06b] transition-all">Skip Animation &gt;&gt;</button>)}
                        </div>
                    </div>
                </div>
            </div>
            <style>{`@keyframes scan { 0% { top: 0%; opacity: 0; } 10% { opacity: 1; } 90% { opacity: 1; } 100% { top: 100%; opacity: 0; } } @keyframes scan-gradient { 0% { top: -100%; } 100% { top: 100%; } }`}</style>
        </div>
     );
  };

  if (phase === 'TOURNAMENT_END') return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <div className="absolute top-6 left-6 z-[300]">
              <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
        </div>
        <div className="god-rays opacity-40"></div>
        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] text-center px-4">TOURNAMENT CHAMPIONS</h1>
            <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b] mb-12" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2>
            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">RETURN TO LOBBY</Button>
        </div>
      </div>
  );

  const overlayBackButton = (
      <div className="fixed top-6 left-6 z-[300]">
            <Button variant="outline" size="sm" onClick={onMinimize} className="bg-black/80 border-[#dcb06b] text-[#dcb06b] hover:bg-[#dcb06b] hover:text-black">LOBBY</Button>
      </div>
  );

  if (phase === 'TEAM_REVEAL') return renderTeamRevealScreen();
  if (phase === 'MATCHUP_LOTTERY') return renderMatchupLottery();
  if (phase === 'TRANSITION' && activeMatchData) return <>{overlayBackButton}<PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} azureTeamName={activeMatchData.teamA?.name || 'TBD'} crimsonTeamName={activeMatchData.teamB?.name || 'TBD'} onComplete={() => setPhase('DECLARE_WIN')} /></>;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <>{overlayBackButton}<MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} /></>;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} azureTeamName={activeMatchData.teamA?.name} crimsonTeamName={activeMatchData.teamB?.name} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <>{overlayBackButton}<EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now(), azureTeamName: activeMatchData.teamA?.name, crimsonTeamName: activeMatchData.teamB?.name }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} /></>;

  const isDeepBracket = match.teams.length >= 14;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
          <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
            <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
            <input type="text" value={renameState.newName} onChange={e => setRenameState({ ...renameState, newName: e.target.value })} className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center" autoFocus />
            <div className="flex gap-3">
              <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
              <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
            </div>
          </div>
        </div>
      )}

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="absolute top-8 left-8"><Button variant="outline" size="sm" onClick={onMinimize}>LOBBY</Button></div>
          <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-16 uppercase">TOURNAMENT BRACKET</h1>
          <div className={`flex items-center justify-center relative py-20 ${isDeepBracket ? 'gap-20 md:gap-28' : 'gap-16 md:gap-24'}`}>
            {hasRoundOne && (
                <div className={`flex flex-col relative ${isDeepBracket ? 'gap-8' : 'gap-8'}`}>
                    {roundOneMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {match.teams.length === 14 ? (
                                <>
                                    {i < 4 && i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>}
                                    {i >= 4 && <EnergyConnector type="straight" height={218} style={{top:'50%'}}/>}
                                </>
                            ) : (
                                i % 2 === 0 && <EnergyConnector type="fork" height={218} style={{top:'50%'}}/>
                            )}
                        </div>
                    ))}
                </div>
            )}
            <div className={`flex flex-col relative ${isDeepBracket ? 'gap-[274px]' : 'gap-32'}`}>
                {quarterMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i % 2 === 0 && <EnergyConnector type="fork" height={isDeepBracket ? 458 : 338} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className={`flex flex-col relative ${isDeepBracket ? 'gap-[758px]' : 'gap-64'}`}>
                {semiMatches.map((m, i) => (
                    <div key={m.id} className="relative">
                        {renderBracketMatchCard(m)}
                        {i === 0 && <EnergyConnector type="fork" height={isDeepBracket ? 938 : 458} style={{top:'50%'}}/>}
                    </div>
                ))}
            </div>
            <div className="relative scale-125 ml-10">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState?.isOpen && <SpinWheel {...wheelState} roleName={wheelState.role} roomId={activeRoomId} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}

            {/* Top Navigation */}
            <div className="absolute top-8 left-8 z-50">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
            </div>

            {/* CENTERED ROOM ID HIGHLIGHT */}
            <div className="absolute top-6 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center">
                <div className="relative group">
                    <div className="absolute -inset-[2px] bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none group-hover:opacity-40 transition-opacity"></div>
                    <div className="relative bg-[#05090f]/90 border-2 border-[#dcb06b] px-10 py-3 clip-corner-sm flex flex-col items-center shadow-[0_0_30px_rgba(220,176,107,0.3)]">
                        <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-80">ROOM ID</span>
                        <input 
                            type="text" 
                            value={activeRoomId === 'AUTO' ? '' : matchRoomIds[currentMatchIdx] || ''} 
                            onChange={(e) => setMatchRoomIds(prev => ({ ...prev, [currentMatchIdx]: e.target.value.replace(/\D/g,'').slice(0,4) }))}
                            className="bg-transparent border-none text-white font-orbitron font-black text-3xl tracking-[0.3em] w-32 text-center focus:outline-none placeholder-white/20"
                            placeholder="----"
                        />
                    </div>
                </div>
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10 mt-16">
                <div className="grid grid-cols-2 gap-20 items-end mb-4">
                    <div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-cyan-400 leading-tight">{activeMatchData?.teamA?.name}</h2></div>
                    <div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-red-500 leading-tight">{activeMatchData?.teamB?.name}</h2></div>
                </div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-20"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>

            <div className="fixed bottom-10 left-0 right-0 flex justify-center">
                 <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
            </div>
        </div>
      )}
      <ConfirmModal isOpen={showAbortConfirm} title="ABORT TOURNAMENT" message="End tournament?" onConfirm={onReset} onCancel={() => setShowAbortConfirm(false)} isDestructive />
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { TeamSlot, Role } from '../types';
import { Button } from './Button';
import { RoleIcons, ROLES_ORDER } from '../constants';

interface PortalTransitionProps {
  onComplete: () => void;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
  azureTeamName: string;
  crimsonTeamName: string;
}

export const PortalTransition: React.FC<PortalTransitionProps> = ({ onComplete, azureTeam, crimsonTeam, azureTeamName, crimsonTeamName }) => {
  const [stage, setStage] = useState(0);

  // Stream State
  const [showConfig, setShowConfig] = useState(false);
  const [showPlayer, setShowPlayer] = useState(false); // Controls the video popup
  const [streamUrl, setStreamUrl] = useState('');
  const [videoId, setVideoId] = useState<string | null>(null);

  useEffect(() => {
    // Animation sequence
    const t1 = setTimeout(() => setStage(1), 100);
    const t2 = setTimeout(() => setStage(2), 800);

    return () => {
        clearTimeout(t1);
        clearTimeout(t2);
    };
  }, []);

  const handleNext = () => {
    setStage(3); // Fade out
    setTimeout(() => {
        onComplete();
    }, 500);
  };

  const extractVideoId = (url: string) => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const handleStreamSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      const id = extractVideoId(streamUrl);
      if (id) {
          setVideoId(id);
          setShowConfig(false);
          setShowPlayer(true); // Auto open player on success
      } else {
          if (!streamUrl.trim()) setVideoId(null);
          setShowConfig(false);
      }
  };

  const renderTeamGrid = (teamSlots: TeamSlot[], teamColor: 'cyan' | 'red') => {
      const displaySlots = [...teamSlots].sort((a, b) => {
          if (a.role === Role.COACH) return 1;
          if (b.role === Role.COACH) return -1;
          return ROLES_ORDER.indexOf(a.role) - ROLES_ORDER.indexOf(b.role);
      });

      const isCyan = teamColor === 'cyan';

      return (
        <div className="grid grid-cols-5 gap-3 md:gap-6 w-full max-w-6xl mx-auto px-6 relative z-10">
            {displaySlots.map((slot, idx) => {
                const isCoach = slot.role === Role.COACH;
                const isMvp = slot.player.isLastMatchMvp;

                let borderClass = isCyan 
                    ? 'border-[#00d2ff]/30 shadow-[0_0_15px_rgba(0,210,255,0.1)]' 
                    : 'border-[#ef4444]/30 shadow-[0_0_15px_rgba(239,68,68,0.1)]';

                if (isMvp && !isCoach) {
                    borderClass = 'border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.5)]';
                }

                return (
                    <div 
                        key={idx} 
                        className={`
                            relative flex flex-col items-center
                            w-full aspect-[3/4]
                            clip-corner-sm backdrop-blur-md
                            border transition-all duration-500 transform group
                            ${stage >= 2 ? 'opacity-100 scale-100 translate-y-0' : `opacity-0 scale-75 ${isCyan ? '-translate-y-10' : 'translate-y-10'}`}
                            ${isCyan ? 'bg-[#0a1a2f]/60' : 'bg-[#1a0505]/60'}
                            ${borderClass}
                        `}
                        style={{ transitionDelay: `${900 + (idx * 50)}ms` }}
                    >
                        <div className={`absolute inset-0 bg-gradient-to-b ${isCyan ? 'from-[#00d2ff]/10' : 'from-[#ef4444]/10'} to-transparent opacity-50`}></div>
                        <div className={`w-full h-1 ${isCyan ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'} opacity-70`}></div>
                        <div className="flex-1 flex flex-col items-center justify-center p-2 w-full relative z-10">
                            <div className={`
                                mb-2 transform transition-transform duration-300 group-hover:scale-110 
                                ${isCyan ? 'text-[#00d2ff] drop-shadow-[0_0_8px_rgba(0,210,255,0.6)]' : 'text-[#ef4444] drop-shadow-[0_0_8px_rgba(239,68,68,0.6)]'}
                                opacity-90
                            `}>
                                <div className="scale-110 md:scale-125">
                                   {RoleIcons[slot.role]}
                                </div>
                            </div>
                            <div className="w-full flex justify-between px-2 mb-2 opacity-30">
                                <div className={`h-[1px] w-3 ${isCyan ? 'bg-cyan-400' : 'bg-red-500'}`}></div>
                                <div className={`h-[1px] w-3 ${isCyan ? 'bg-cyan-400' : 'bg-red-500'}`}></div>
                            </div>
                            <div className="w-full relative">
                                <div className="absolute inset-0 bg-black/60 blur-sm"></div>
                                {/* Discord Info */}
                                {slot.player.discordName && (
                                    <div className="relative z-10 flex justify-center items-center gap-1 mb-0.5 opacity-80">
                                        <svg className="w-2.5 h-2.5 text-[#5865F2]" viewBox="0 0 127 96" fill="none" xmlns="http://www.w3.org/2000/svg">
                                            <path d="M107.701 8.04901C107.701 8.04901 98.7997 0.941655 88.5997 0C88.1997 0.541667 87.2997 2.04902 86.2997 3.34902C75.2997 1.84902 64.3997 1.84902 53.6997 3.34902C52.6997 2.04902 51.7997 0.541667 51.3997 0C41.1997 0.941655 32.2997 8.04901 32.2997 8.04901C13.8997 35.549 14.3997 62.449 16.8997 88.949C28.2997 97.449 43.0997 102.449 57.8997 102.449C61.3997 97.749 64.3997 92.749 66.8997 87.449C61.6997 85.449 56.7997 82.949 52.1997 80.049C53.4997 79.149 54.6997 78.149 55.7997 77.149C82.3997 89.449 111.4 89.449 137.6 77.149C138.8 78.249 140 79.249 141.3 80.049C136.7 82.949 131.8 85.449 126.6 87.449C129.1 92.749 132.1 97.749 135.6 102.449C150.4 102.449 165.2 97.449 176.6 88.949C179.3 61.249 174.5 35.549 156.1 8.04901C156.1 8.04901 147.2 0.941655 137 0C136.6 0.541667 135.7 2.04902 134.7 3.34902C124 1.84902 113.1 1.84902 102.1 3.34902C101.1 2.04902 100.2 0.541667 99.8003 0C89.6003 0.941655 80.7003 8.04901 80.7003 8.04901ZM64.0997 68.349C56.2997 68.349 49.8997 61.249 49.8997 52.549C49.8997 43.849 56.0997 36.749 64.0997 36.749C72.0997 36.749 78.4997 43.849 78.2997 52.549C78.2997 61.249 72.0997 68.349 64.0997 68.349ZM124.3 68.349C116.5 68.349 110.1 61.249 110.1 52.549C110.1 43.849 116.3 36.749 124.3 36.749C132.3 36.749 138.7 43.849 138.5 52.549C138.5 61.249 132.3 68.349 124.3 68.349Z" fill="currentColor" />
                                        </svg>
                                        <span className="text-[8px] text-white/70 font-orbitron">{slot.player.discordName}</span>
                                    </div>
                                )}
                                <span className="relative z-10 block text-[9px] md:text-xs font-orbitron font-bold text-white truncate w-full text-center tracking-wider py-1">
                                    {slot.player.name}
                                </span>
                            </div>
                        </div>
                        <div className={`absolute bottom-0 left-0 w-2 h-2 border-b border-l ${isCyan ? 'border-[#00d2ff]' : 'border-[#ef4444]'}`}></div>
                        <div className={`absolute bottom-0 right-0 w-2 h-2 border-b border-r ${isCyan ? 'border-[#00d2ff]' : 'border-[#ef4444]'}`}></div>
                        {isCoach && (
                            <div className="absolute top-2 right-2 text-[8px] font-black uppercase text-white bg-white/20 px-1 rounded">COACH</div>
                        )}
                    </div>
                );
            })}
        </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center overflow-hidden font-inter select-none">

        {/* --- GLOBAL BACKGROUND EFFECTS --- */}
        <div className="absolute inset-0 opacity-20 pointer-events-none" 
            style={{ backgroundImage: 'linear-gradient(#1e3a5f 1px, transparent 1px), linear-gradient(90deg, #1e3a5f 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
        </div>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_90%)] z-0 pointer-events-none"></div>
        <div className={`absolute inset-0 bg-white pointer-events-none z-[60] mix-blend-overlay ${stage === 2 ? 'animate-[impact-flash_0.3s_ease-out_forwards]' : 'opacity-0'}`}></div>

        {/* --- MAIN ANIMATION CONTAINER --- */}
        <div className={`
            absolute inset-0 flex flex-col w-full h-full z-10 pointer-events-none
            ${stage === 2 ? 'animate-[clash-shake_0.4s_ease-in-out]' : ''}
            transition-opacity duration-700
            ${stage === 3 ? 'opacity-0 scale-105' : 'opacity-100 scale-100'}
        `}>

            {/* TOP HALF (AZURE) */}
            <div className={`
                absolute top-0 left-0 right-0 h-[50vh]
                bg-gradient-to-b from-[#0a1a2f] via-[#0a1a2f]/80 to-[#00d2ff]/10
                flex flex-col items-center justify-end
                transform transition-all duration-500 cubic-bezier(0.22, 1, 0.36, 1)
                ${stage >= 1 ? 'translate-y-0' : '-translate-y-full'}
                z-10 pb-16
            `}>
                <div className="absolute top-[15%] flex flex-col items-center w-full px-10 text-center">
                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#00d2ff] tracking-[0.2em] drop-shadow-[0_0_20px_rgba(0,210,255,0.5)] uppercase max-w-full leading-tight break-words">{azureTeamName}</h2>
                    <div className="text-[#00d2ff] text-xs font-orbitron tracking-[0.5em] opacity-70 mt-2">AZURE GOLEM</div>
                </div>
                {renderTeamGrid(azureTeam, 'cyan')}
                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#00d2ff] shadow-[0_0_30px_#00d2ff] z-20"></div>
            </div>

            {/* BOTTOM HALF (CRIMSON) */}
            <div className={`
                absolute bottom-0 left-0 right-0 h-[50vh] 
                bg-gradient-to-t from-[#1a0505] via-[#1a0505]/80 to-[#ef4444]/10
                flex flex-col items-center justify-start
                transform transition-all duration-500 cubic-bezier(0.22, 1, 0.36, 1)
                ${stage >= 1 ? 'translate-y-0' : 'translate-y-full'}
                z-10 pt-16
            `}>
                 <div className="absolute top-0 left-0 right-0 h-[2px] bg-[#ef4444] shadow-[0_0_30px_#ef4444] z-20"></div>
                 {renderTeamGrid(crimsonTeam, 'red')}
                 <div className="absolute bottom-[25%] flex flex-col items-center w-full px-10 text-center">
                     <div className="text-[#ef4444] text-xs font-orbitron tracking-[0.5em] opacity-70 mb-2">CRIMSON GOLEM</div>
                     <h2 className="text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-[#ef4444] to-[#7f1d1d] tracking-[0.2em] drop-shadow-[0_0_20px_rgba(239,68,68,0.5)] uppercase max-w-full leading-tight break-words">{crimsonTeamName}</h2>
                 </div>
            </div>

            {/* CENTER UI (VS) */}
            <div className={`
                absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[50]
                flex items-center justify-center transform transition-all duration-300
                ${stage >= 2 ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}
            `}>
                <div className={`absolute inset-0 border-2 border-[#dcb06b] rounded-full opacity-0 ${stage === 2 ? 'animate-[ping_1s_cubic-bezier(0,0,0.2,1)_infinite]' : ''}`}></div>
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center">
                    <div className="absolute inset-0 bg-[#05090f] rotate-45 border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.5)] animate-[spin_8s_linear_infinite]"></div>
                    <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45 bg-black/40 backdrop-blur-sm"></div>
                    <span className="relative z-10 text-transparent bg-clip-text bg-gradient-to-br from-[#f3dcb1] to-[#dcb06b] font-orbitron font-black text-4xl md:text-5xl italic drop-shadow-sm pr-1 pt-1">VS</span>
                    <div className="absolute top-1/2 left-[-40px] w-10 h-[2px] bg-gradient-to-l from-[#dcb06b] to-transparent"></div>
                    <div className="absolute top-1/2 right-[-40px] w-10 h-[2px] bg-gradient-to-r from-[#dcb06b] to-transparent"></div>
                </div>
            </div>

            {/* Enter Button (Bottom Center) */}
            <div className={`
                absolute bottom-10 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-6 pointer-events-auto
                transform transition-all duration-700 delay-300
                ${stage >= 2 ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0'}
            `}>
                <Button 
                    onClick={handleNext} 
                    className="w-full py-6 text-xl font-black tracking-[0.3em] border-2 border-[#dcb06b] text-[#dcb06b] bg-[#0a1a2f]/90 hover:bg-[#dcb06b] hover:text-black shadow-[0_0_30px_rgba(220,176,107,0.2)] hover:shadow-[0_0_50px_rgba(220,176,107,0.6)] transition-all duration-300 clip-corner-md"
                >
                    ENTER BATTLEFIELD
                </Button>
            </div>
        </div>

        {/* --- CONFIG MODAL & VIDEO PLAYER REMAIN UNCHANGED BUT OMITTED FOR BREVITY --- */}

        {/* Global Keyframes */}
        <style>{`
            @keyframes impact-flash { 0% { opacity: 0; } 50% { opacity: 0.8; } 100% { opacity: 0; } }
            @keyframes clash-shake {
                0%, 100% { transform: translate(0, 0); }
                10%, 30%, 50%, 70%, 90% { transform: translate(-4px, -4px); }
                20%, 40%, 60%, 80% { transform: translate(4px, 4px); }
            }
            @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        `}</style>
    </div>
  );
};
